import{_ as a,o,c as i,ag as n}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Profile","description":"","frontmatter":{},"headers":[],"relativePath":"account/profile.md","filePath":"account/profile.md"}'),t={name:"account/profile.md"};function r(l,e,s,c,p,u){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h1><p>Manage your personal account settings, preferences, and notifications.</p><h2 id="personal-information" tabindex="-1">Personal information <a class="header-anchor" href="#personal-information" aria-label="Permalink to &quot;Personal information&quot;">​</a></h2><p>Update your profile from the <strong>Profile</strong> page:</p><ul><li><strong>Name</strong> — Your display name</li><li><strong>Email</strong> — Your login email</li><li><strong>Profile picture</strong> — Upload a photo or avatar</li><li><strong>Language</strong> — Interface language (English, Dutch, German, French)</li></ul><h3 id="changing-your-language" tabindex="-1">Changing your language <a class="header-anchor" href="#changing-your-language" aria-label="Permalink to &quot;Changing your language&quot;">​</a></h3><ol><li>Go to <strong>Profile</strong></li><li>Select your preferred language</li><li>The interface updates immediately</li></ol><p>Your language setting affects:</p><ul><li>All UI text and navigation</li><li>Date and number formatting</li><li>Default language for new documents</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Invoice language is set per invoice and can differ from your interface language. You can send a Dutch invoice while using the English interface.</p></div><h2 id="password" tabindex="-1">Password <a class="header-anchor" href="#password" aria-label="Permalink to &quot;Password&quot;">​</a></h2><p>Change your password:</p><ol><li>Go to <strong>Profile &gt; Password</strong></li><li>Enter your current password</li><li>Enter and confirm your new password</li><li>Click <strong>Save</strong></li></ol><p>If you signed up with Google or Microsoft, you can still set a password for email-based login.</p><h2 id="notification-preferences" tabindex="-1">Notification preferences <a class="header-anchor" href="#notification-preferences" aria-label="Permalink to &quot;Notification preferences&quot;">​</a></h2><p>Control which notifications you receive and how:</p><h3 id="email-notifications" tabindex="-1">Email notifications <a class="header-anchor" href="#email-notifications" aria-label="Permalink to &quot;Email notifications&quot;">​</a></h3><ul><li><strong>Invoice paid</strong> — When a customer pays an invoice</li><li><strong>Quote request received</strong> — When someone requests a quote from your business page</li><li><strong>Team activity</strong> — When team members perform actions</li><li><strong>Expense approved</strong> — When an expense is approved</li></ul><h3 id="email-digest" tabindex="-1">Email digest <a class="header-anchor" href="#email-digest" aria-label="Permalink to &quot;Email digest&quot;">​</a></h3><p>Choose how frequently you receive summary emails:</p><ul><li><strong>Daily</strong> — Daily summary of activity</li><li><strong>Weekly</strong> — Weekly roundup</li><li><strong>Monthly</strong> — Monthly overview</li><li><strong>Off</strong> — No digest emails</li></ul><h3 id="push-notifications" tabindex="-1">Push notifications <a class="header-anchor" href="#push-notifications" aria-label="Permalink to &quot;Push notifications&quot;">​</a></h3><p>Enable browser push notifications for real-time alerts when you have the app open.</p><h3 id="in-app-notifications" tabindex="-1">In-app notifications <a class="header-anchor" href="#in-app-notifications" aria-label="Permalink to &quot;In-app notifications&quot;">​</a></h3><p>Real-time notifications within the MyCompanyDesk interface. These are always on and appear in the notification bell in the header.</p><h2 id="connected-apps" tabindex="-1">Connected apps <a class="header-anchor" href="#connected-apps" aria-label="Permalink to &quot;Connected apps&quot;">​</a></h2><p>View and manage OAuth connections:</p><ul><li><strong>Google</strong> — Connected for login and/or Gmail sending</li><li><strong>Microsoft</strong> — Connected for login and/or Outlook sending</li></ul><p>Revoke access to disconnect an app from your account.</p>',29)])])}const d=a(t,[["render",r]]);export{h as __pageData,d as default};
